import{_ as a,o as r,c as t,ag as o}from"./chunks/framework.BLeoozAw.js";const h=JSON.parse('{"title":"子域名枚举：敏感信息泄露扩大战果，最终获得4000美元","description":"","frontmatter":{},"headers":[],"relativePath":"experience/敏感信息泄露/swagger-leak.md","filePath":"experience/敏感信息泄露/swagger-leak.md"}'),n={name:"experience/敏感信息泄露/swagger-leak.md"};function s(p,e,l,i,c,d){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="子域名枚举-敏感信息泄露扩大战果-最终获得4000美元" tabindex="-1">子域名枚举：敏感信息泄露扩大战果，最终获得4000美元 <a class="header-anchor" href="#子域名枚举-敏感信息泄露扩大战果-最终获得4000美元" aria-label="Permalink to &quot;子域名枚举：敏感信息泄露扩大战果，最终获得4000美元&quot;">​</a></h1><p>最近我幸运地发现了一个漏洞，并通过该漏洞的漏洞赏金计划赚取了超过 4000 美元的赏金。该漏洞是一个简单的信息泄露漏洞，影响的程序允许使用通配符子域名访问，例如 *.REDACTED.com。由于该程序的性质是私密的，所以我无法分享具体程序的细节。然而，整个漏洞发现的过程和结果都非常令人满意。</p><p>在手工信息侦察 (Manual Recon) 的过程中，我发现了一个泄露敏感信息的端点 (Endpoint)。我报告了这个漏洞，并最初获得了 250 美元的赏金。然而，在与我朋友和研究伙伴 Orwa Atiyat 交谈时，我得到了一个改变游戏规则的提示：</p><blockquote><p><strong>尝试在所有子域上使用相同的端点——您可能会幸运。</strong></p></blockquote><p>听取了 Orwa 的建议后，我进行了子域枚举，并将易受攻击的端点附加到我发现的每个子域上，过滤掉 404 错误，并关注具有 403、301 和 200 状态码的响应。对于状态 200，我立即报告了漏洞。对于 301 重定向，只需进行一个简单的调整 - 在子域前面添加 <code>www.</code> 就可以捕获敏感信息。</p><p>真正的挑战来自 403 错误。这就是 [4-ZERO-3]（由 [Dheeraj Madhukar] 创建的工具）发挥宝贵作用的地方。它允许我绕过几乎所有 403 限制，即使在最初的漏洞修复后，也成功绕过了 11 次。</p><p>在此特别感谢 <strong>Orwa Atiyat</strong> 在视频中提供的漏洞侦察建议，以及 <strong>Dheeraj Madhukar</strong> 提供的非常有用的工具，帮助我取得了成功。</p><p>这次经历表明，手动操作、自动化和协作的结合可以将一个不起眼的发现变成可观的收益。</p><h2 id="主要使用的工具" tabindex="-1">主要使用的工具： <a class="header-anchor" href="#主要使用的工具" aria-label="Permalink to &quot;主要使用的工具：&quot;">​</a></h2><ul><li>403 绕过神器：<a href="https://github.com/Dheerajmadhukar/4-ZERO-3" target="_blank" rel="noreferrer">4-ZERO-3</a></li></ul>',10)])])}const g=a(n,[["render",s]]);export{h as __pageData,g as default};
